import { logger } from '@/lib/logger';
import { generateJSON, chatCompletion } from '@/lib/ai/groq-client';

export interface ScriptGenerationParams {
  nr: string;
  topics: string[];
  duration: number;
  audience: string;
  company_context?: string;
}

export interface ContentScriptParams {
  slides?: Array<{ index: number; text: string }>;
  goal?: string;
  language?: string;
  voiceTone?: string;
  simplificationLevel?: string;
  duration?: number;
}

export interface ScriptScene {
  id: string;
  title: string;
  content: string;
  duration: number;
  avatar_instructions: string;
  visual_cues: string[];
  safety_highlights: string[];
}

export interface GeneratedScript {
  title: string;
  scenes: ScriptScene[];
  total_duration: number;
  compliance_notes: string[];
  engagement_tips: string[];
}

export class AIScriptGeneratorService {
  private static isTemplateFallbackEnabled(): boolean {
    return process.env.AI_TEMPLATE_FALLBACK_ENABLED === 'true'
  }

  /**
   * Generate a script using the AI fallback chain: Groq → Gemini → OpenAI
   */
  static async generate(params: ScriptGenerationParams): Promise<GeneratedScript> {
    try {
      logger.info('[AIScriptGenerator] Generating script via AI (Groq→Gemini→OpenAI fallback)');
      return await this.generateWithAI(params);
    } catch (error: unknown) {
      const err = error instanceof Error ? error : new Error(String(error));
      if (process.env.NODE_ENV === 'production' || !this.isTemplateFallbackEnabled()) {
        logger.error('[AIScriptGenerator] AI generation failed in production', err);
        throw err;
      }

      logger.error('[AIScriptGenerator] AI generation failed, using template fallback (explicitly enabled):', err);
      return this.generateTemplate(params);
    }
  }

  private static async generateWithAI(params: ScriptGenerationParams): Promise<GeneratedScript> {
    const systemPrompt = `
      Você é um especialista em Segurança do Trabalho (SST) e Roteirista de Vídeos Profissionais.
      Sua tarefa é criar um roteiro técnico para um vídeo de treinamento sobre NRs (Normas Regulamentadoras).
      
      Estruture a resposta estritamente em JSON com o seguinte formato:
      {
        "title": "Título do Vídeo",
        "total_duration": number (minutos),
        "scenes": [
          {
            "id": "scene-1",
            "title": "Título da Cena",
            "duration": number (minutos),
            "content": "Texto falado pelo avatar...",
            "avatar_instructions": "Como o avatar deve se comportar",
            "visual_cues": ["lista", "de", "elementos", "visuais"],
            "safety_highlights": ["pontos", "chave", "de", "segurança"]
          }
        ],
        "compliance_notes": ["nota 1", "nota 2"],
        "engagement_tips": ["dica 1", "dica 2"]
      }

      O público alvo é: ${params.audience}.
      O contexto da empresa é: ${params.company_context || 'Indústria Geral'}.
    `;

    const userPrompt = `
      Gere um roteiro para a norma ${params.nr}.
      Duração estimada: ${params.duration} minutos.
      Tópicos obrigatórios:
      ${params.topics.map(t => `- ${t}`).join('\n')}
    `;

    const result = await generateJSON<GeneratedScript>(
      systemPrompt,
      userPrompt,
      { temperature: 0.7, max_tokens: 4096 }
    );

    logger.info(`[AIScriptGenerator] Script generated via AI provider`);
    return result;
  }

  /**
   * Template-based script generation.
   * Disabled by default and only used when AI_TEMPLATE_FALLBACK_ENABLED=true in non-production environments.
   */
  private static generateTemplate(params: ScriptGenerationParams): GeneratedScript {
    const isOperational = params.audience.toLowerCase().includes('operador');
    const tone = isOperational ? 'direto e prático' : 'técnico e gerencial';

    const scenes: ScriptScene[] = params.topics.map((topic, index) => ({
      id: `scene-${index + 1}`,
      title: `Módulo ${index + 1}: ${topic}`,
      duration: Math.ceil(params.duration / params.topics.length),
      content: `[Tom ${tone}] Nesta etapa vamos abordar ${topic}, conforme ${params.nr}. É fundamental entender os requisitos de segurança, procedimentos operacionais e medidas preventivas aplicáveis. A prevenção é a melhor ferramenta para evitar acidentes e garantir a conformidade.`,
      avatar_instructions: index === 0 ? 'Apresentação formal, gestos de boas vindas' : 'Postura séria, enfatizando pontos críticos com as mãos',
      visual_cues: ['Slide com Tópicos', `Ícone de ${topic}`, 'Vídeo de fundo: Ambiente Industrial'],
      safety_highlights: [`Risco crítico associado a ${topic}`, 'Procedimento de emergência padrão']
    }));

    // Add Intro and Outro if duration allows
    if (scenes.length > 0) {
      scenes.unshift({
        id: 'scene-intro',
        title: 'Introdução e Objetivos',
        duration: 2,
        content: `Olá equipe. Bem-vindos ao treinamento oficial sobre ${params.nr}. Hoje focaremos na segurança em ${params.company_context || 'nossa operação'}.`,
        avatar_instructions: 'Sorriso profissional, contato visual direto',
        visual_cues: ['Logo da Empresa', 'Título do Treinamento'],
        safety_highlights: ['Compromisso com a Vida', 'Meta Zero Acidentes']
      });
    }

    return {
      title: `Treinamento Oficial: ${params.nr}`,
      total_duration: params.duration,
      scenes: scenes,
      compliance_notes: [
        `Conteúdo alinhado com a revisão 2024 da ${params.nr}`,
        'Necessário validação do SESMT local'
      ],
      engagement_tips: [
        'Realizar quiz prático após cada módulo',
        'Discutir "quase acidentes" relacionados aos temas'
      ]
    };
  }

  /**
   * Generate script from slide content, goal, language, voice tone, and simplification level.
   * Used by the wizard when user has content (from PPTX or manual input).
   */
  static async generateFromContent(params: ContentScriptParams): Promise<GeneratedScript> {
    const lang = params.language || 'pt-BR';
    const tone = params.voiceTone || 'profissional';
    const simplification = params.simplificationLevel || 'original';

    const toneMap: Record<string, string> = {
      profissional: 'Tom profissional, corporativo e direto',
      casual: 'Tom informal, amigável e acessível',
      educativo: 'Tom didático, explicativo e paciente',
      vendas: 'Tom persuasivo, entusiasta e motivador',
    };

    const simplificationMap: Record<string, string> = {
      original: 'Mantenha o nível de complexidade original do conteúdo',
      simplificar: 'Simplifique a linguagem para ser compreensível por qualquer pessoa',
      resumir: 'Resuma o conteúdo mantendo apenas os pontos essenciais',
    };

    const langMap: Record<string, string> = {
      'pt-BR': 'português brasileiro',
      'en-US': 'inglês americano',
      'es-ES': 'espanhol',
    };

    const slideContent = params.slides?.length
      ? params.slides.map(s => `--- Slide ${s.index + 1} ---\n${s.text}`).join('\n\n')
      : '';

    const systemPrompt = `
Você é um roteirista de vídeos profissional. Sua tarefa é gerar um roteiro de narração para um vídeo.

IDIOMA: Escreva todo o roteiro em ${langMap[lang] || lang}.
TOM: ${toneMap[tone] || tone}.
NÍVEL: ${simplificationMap[simplification] || simplification}.
${params.goal ? `OBJETIVO DO VÍDEO: ${params.goal}` : ''}

Responda ESTRITAMENTE em JSON com o formato:
{
  "title": "Título do Vídeo",
  "total_duration": número_em_minutos,
  "scenes": [
    {
      "id": "scene-1",
      "title": "Título da Cena",
      "duration": número_em_minutos,
      "content": "Texto da narração falado pelo apresentador...",
      "avatar_instructions": "Como o avatar deve se comportar",
      "visual_cues": ["elemento visual 1", "elemento visual 2"],
      "safety_highlights": []
    }
  ],
  "compliance_notes": [],
  "engagement_tips": ["dica 1"]
}

${slideContent ? 'CADA slide deve gerar UMA cena correspondente. Mantenha a segmentação slide-a-slide.' : 'Gere entre 3-8 cenas adequadas ao conteúdo.'}
`;

    const userPrompt = slideContent
      ? `Gere o roteiro de narração para o seguinte conteúdo de slides:\n\n${slideContent}`
      : `Gere um roteiro de narração para um vídeo ${params.goal ? `sobre "${params.goal}"` : 'institucional'}. Duração estimada: ${params.duration || 5} minutos.`;

    try {
      const result = await generateJSON<GeneratedScript>(
        systemPrompt,
        userPrompt,
        { temperature: 0.7, max_tokens: 4096 }
      );

      logger.info('[AIScriptGenerator] Script generated from content via AI', {
        scenesCount: result.scenes?.length,
        language: lang,
        tone,
        simplification,
      });

      return result;
    } catch (error: unknown) {
      const err = error instanceof Error ? error : new Error(String(error));
      const errMsg = err.message.toLowerCase();

      // Handle rate limit (429) specifically
      if (errMsg.includes('429') || errMsg.includes('rate limit') || errMsg.includes('quota')) {
        logger.warn('[AIScriptGenerator] Rate limit hit on AI provider', { error: err.message });
        throw new Error('Limite de requisições atingido. Aguarde alguns minutos e tente novamente.');
      }

      // Handle timeout specifically
      if (errMsg.includes('timeout') || errMsg.includes('aborted')) {
        logger.warn('[AIScriptGenerator] AI request timed out', { error: err.message });
        throw new Error('A geração excedeu o tempo limite. Tente novamente com menos conteúdo.');
      }

      logger.error('[AIScriptGenerator] Content-based generation failed', err);
      throw err;
    }
  }
}
